@startuml

abstract class DaoSupport {
  + void save(Object e)
  + void delete(Integer id)
}

interface PersonService {
  + void delete(Integer id)
}

class PersonServiceBean {
  + void delete(Integer id)
}

note "泛化即继承关系" as N1
note "实现关系" as N2

PersonServiceBean --|> DaoSupport
PersonServiceBean ..|> PersonService

PersonServiceBean .. N1
N1 .. DaoSupport

PersonServiceBean .. N2
N2 .. PersonService

@enduml
